#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int a, b, c, d;
        scanf("%d %d %d %d", &a, &b, &c, &d);
        int found = 0;
        for (int mask = 1; mask < (1 << 4); mask++) {
            int sum = 0;
            if (mask & (1 << 0)) sum += a;
            if (mask & (1 << 1)) sum += b;
            if (mask & (1 << 2)) sum += c;
            if (mask & (1 << 3)) sum += d;
            if (sum == 0) {
                found = 1;
                break;
            }
        }
        if (found) printf("Yes\n");
        else printf("No\n");
    }
    return 0;
}

