import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int a = sc.nextInt();
            int b = sc.nextInt();
            int c = sc.nextInt();
            int d = sc.nextInt();
            boolean found = false;
            for (int mask = 1; mask < (1 << 4); mask++) {
                int sum = 0;
                if ((mask & (1 << 0)) != 0) sum += a;
                if ((mask & (1 << 1)) != 0) sum += b;
                if ((mask & (1 << 2)) != 0) sum += c;
                if ((mask & (1 << 3)) != 0) sum += d;
                if (sum == 0) {
                    found = true;
                    break;
                }
            }
            if (found) System.out.println("Yes");
            else System.out.println("No");
        }
    }
}

